// Filter Already Notified Publishers
// Compares incoming pending publishers against the IDs we've already alerted on,
// which are persisted in this workflow's static data.

const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.notifiedPublisherIds)) {
  staticData.notifiedPublisherIds = [];
}
const notified = new Set(staticData.notifiedPublisherIds.map(String));

// AWIN returns either an array directly or an object with a publishers field.
// Normalize both shapes into a flat array of publisher objects.
const incoming = [];
for (const item of $input.all()) {
  const payload = item.json;
  if (Array.isArray(payload)) {
    incoming.push(...payload);
  } else if (Array.isArray(payload?.publishers)) {
    incoming.push(...payload.publishers);
  } else if (payload && typeof payload === 'object' && payload.id) {
    incoming.push(payload);
  }
}

const seenThisRun = new Set();
const newPublishers = incoming.filter((p) => {
  const id = String(p?.id ?? p?.publisherId ?? '');
  if (!id) return false;
  if (notified.has(id)) return false;
  if (seenThisRun.has(id)) return false;
  seenThisRun.add(id);
  return true;
});

return [
  {
    json: {
      count: newPublishers.length,
      newPublishers,
      alreadyNotifiedCount: notified.size,
    },
  },
];

// Format Email Body
// Builds a clean HTML email body and a dynamic subject line
// summarizing the new pending publishers.

const input = $input.first().json;
const publishers = Array.isArray(input.newPublishers) ? input.newPublishers : [];
const count = publishers.length;

const escapeHtml = (value) =>
  String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');

const formatDate = (value) => {
  if (!value) return '—';
  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return escapeHtml(value);
  return d.toISOString().slice(0, 10);
};

const rows = publishers
  .map((p) => {
    const id = escapeHtml(p.id ?? p.publisherId ?? '');
    const name = escapeHtml(p.name ?? p.publisherName ?? 'Unknown');
    const country = escapeHtml(p.country ?? p.primaryRegion?.countryCode ?? '—');
    const joined = formatDate(p.joinDate ?? p.applicationDate ?? p.dateJoined ?? p.createdDate);
    return `
      <tr>
        <td style="padding:10px;border-bottom:1px solid #eee;">${id}</td>
        <td style="padding:10px;border-bottom:1px solid #eee;">${name}</td>
        <td style="padding:10px;border-bottom:1px solid #eee;">${country}</td>
        <td style="padding:10px;border-bottom:1px solid #eee;">${joined}</td>
      </tr>`;
  })
  .join('');

const subject = `🔔 [AWIN] ${count} New Publisher(s) Pending Approval`;

const htmlBody = `<!DOCTYPE html>
<html>
  <body style="margin:0;padding:0;background:#f6f8fa;font-family:Arial,Helvetica,sans-serif;color:#333;">
    <div style="max-width:600px;margin:0 auto;padding:24px;background:#ffffff;">
      <h2 style="color:#333;margin:0 0 16px 0;">🔔 ${count} new publisher(s) pending approval on AWIN</h2>
      <p style="color:#333;margin:0 0 16px 0;">The following publishers have applied to your AWIN program and are awaiting review:</p>
      <table role="presentation" style="width:100%;border-collapse:collapse;font-size:14px;color:#333;">
        <thead>
          <tr style="background:#f0f4f8;">
            <th align="left" style="padding:10px;border-bottom:2px solid #ddd;">Publisher ID</th>
            <th align="left" style="padding:10px;border-bottom:2px solid #ddd;">Name</th>
            <th align="left" style="padding:10px;border-bottom:2px solid #ddd;">Country</th>
            <th align="left" style="padding:10px;border-bottom:2px solid #ddd;">Applied</th>
          </tr>
        </thead>
        <tbody>${rows}</tbody>
      </table>
      <p style="margin:24px 0 0 0;">
        <a href="https://ui.awin.com" style="color:#0073e6;text-decoration:none;font-weight:bold;">Open AWIN Dashboard →</a>
      </p>
      <p style="color:#888;font-size:12px;margin-top:32px;">Automated alert from your n8n AWIN workflow.</p>
    </div>
  </body>
</html>`;

return [
  {
    json: {
      subject,
      htmlBody,
      count,
      newPublishers: publishers,
    },
  },
];

// Update Notified Publisher IDs
// Persists the IDs we just alerted on into workflow static data
// so future runs do not re-alert for the same publishers.

const payload = $input.first().json;
const newPublishers = Array.isArray(payload.newPublishers) ? payload.newPublishers : [];

const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.notifiedPublisherIds)) {
  staticData.notifiedPublisherIds = [];
}

const existing = new Set(staticData.notifiedPublisherIds.map(String));
const addedIds = [];

for (const p of newPublishers) {
  const id = String(p?.id ?? p?.publisherId ?? '');
  if (!id || existing.has(id)) continue;
  existing.add(id);
  addedIds.push(id);
}

staticData.notifiedPublisherIds = Array.from(existing);
staticData.lastNotifiedAt = new Date().toISOString();

return [
  {
    json: {
      addedIds,
      addedCount: addedIds.length,
      totalNotified: staticData.notifiedPublisherIds.length,
      lastNotifiedAt: staticData.lastNotifiedAt,
      newPublishers,
    },
  },
];

// Expand the new-publisher list into one item per publisher
// so the Google Sheets node can append a row for each.

const payload = $input.first().json;
const publishers = Array.isArray(payload.newPublishers) ? payload.newPublishers : [];
const notifiedAt = payload.lastNotifiedAt || new Date().toISOString();

return publishers.map((p) => ({
  json: {
    publisherId: String(p?.id ?? p?.publisherId ?? ''),
    name: p?.name ?? p?.publisherName ?? '',
    country: p?.country ?? p?.primaryRegion?.countryCode ?? '',
    status: p?.relationship ?? p?.relationshipStatus ?? 'pending',
    notifiedAt,
  },
}));

